validateV2Checkout(){const response=this.wcForms.checkout?.querySelector('[name="g-recaptcha-response"]')?.value;if(!response){alert("Please complete the reCAPTCHA verification.");return false;}
return true;}
async validateV3Checkout(){try{const token=await this.executeRecaptcha("wc_checkout");this.updateTokenInput(this.wcForms.checkout,token);return true;}catch(error){console.error("reCAPTCHA error:",error);return false;}}
